SELECT MIN(oMonetaryAmount.hasamount) AS AggResult1, oListedSecurity.haslegalname AS oListedSecurity_hasLegalName FROM fiben.listedsecurity AS oListedSecurity INNER JOIN fiben.monetaryamount AS oMonetaryAmount ON oListedSecurity.haslasttradedvalue = oMonetaryAmount.monetaryamountid GROUP BY oListedSecurity.haslegalname ORDER BY CASE WHEN AggResult1 IS NULL THEN 1 ELSE 0 END, AggResult1 ASC
